+bool undefinedParameterExists(const_symbol_list * csl)
+{
+
+     for(const_symbol_list::iterator cs =  csl->begin(); cs != csl->end(); ++cs)
+     {
+       if(!(*cs)) return true;
+     };
+
+     return false;
+};
