+  for(vector<const_symbol_list*>::const_iterator csl = vcsl.begin(); csl != vcsl.end(); ++csl)
+  {     
+     someDefinedLists = defineUndefinedParametersPropVar(*csl,op,vld,g,dp,neg,svs,compError);
