+CoScalar Polynomial::getCoeff(unsigned int pow) const
+{
+	map<unsigned int,CoScalar>::const_iterator i = coeffs.find(pow);
+
+	if(i != coeffs.end())
+		return i->second;
+	else
+		return 0;
