+bool Polynomial::operator==(const Polynomial & p) const
+{
+	if(getDegree() != p.getDegree()) return false;
+
+	for(unsigned int i = getDegree(); i >= 0; --i)
+	{
+		if(getCoeff(i) != p.getCoeff(i)) return false;
