+CoScalar Polynomial::evaluate(CoScalar t) const
+{
+	CoScalar ans = 0;
+
+	for(map<unsigned int,CoScalar>::const_iterator i = coeffs.begin(); i != coeffs.end();++i)
+	{
+		ans += CoScalar((i->second)*pow(t,i->first));
+	};
+
+	return ans;
+};
