+void Polynomial::write(ostream & o) const
+{
+	if(coeffs.size()==0)
+	{
+		o << "0";
+	}
+	else
+	{
+		map<unsigned int,CoScalar>::const_iterator i = coeffs.end();
+		for(unsigned int count=0; count != coeffs.size(); ++count)
+		{
+			--i;
+
+			if( count != 0)
+			{
+				if(i->second >= 0)
+					o << " + ";
+				else
+					o << " - ";
+			}
+			else if(i->second < 0)
+			{
+					o << " - ";
+			};
+
+			if(i->second >= 0)
+			{
+				if( (i->second != 1) || (i->first == 0) ) o << i->second;
+			}
+			else
+ 			{
+ 				if( (i->second != -1) || (i->first == 0) ) o << -(i->second);
+ 			};
+
+			if(i->first == 1)
+				o << "t";
+
+ 			else if(i->first != 0)
+ 				o << "t^" << i->first;
+
+			if( i == coeffs.begin()) break;
+
+
+		};
+
+	};
