+Polynomial Polynomial::removeRepeatedRoots() const
+{
+
+	Polynomial d = diff();
+	Polynomial gcd = getGCD(d);
+	Polynomial ans;
+
+	if(gcd.getDegree() > 0)
+	{
+		ans = divide(gcd).first;
+	}
+
+	else
+	{
+		ans = *this;
+	};
+
+
+	return ans;
+};
