+void PrettyPrinter::write_assignment(ostream & o,const assignment * p)
+{
+
+ 	o << "(";
+	switch(p->getOp())
+	{
+		case E_ASSIGN:
+			if(inInitial) 
+			{
+				o << "= ";
+			}
+			else 
+			{
+				o << "assign ";
+			};
+			break;
+		case E_INCREASE:
+			o << "increase ";
+			break;
+		case E_DECREASE:
+			o << "decrease ";
+			break;
+		case E_SCALE_UP:
+			o << "scale-up ";
+			break;
+		case E_SCALE_DOWN:
+			o << "scale-down ";
+			break;
+		default:
+			break;
+	};
+	p->getFTerm()->write(o);
+	o << " ";
+	p->getExpr()->write(o);
+	o << ")";
+
+};
+
+struct Writer {
+	ostream & o;
+
+	Writer(ostream & oo) : o(oo) {};
+
+	template<class typ>
+	void operator()(const typ * p) {o << " "; p->typ::write(o);};
+};
+
+struct NotWriter {
+	ostream & o;
+
+	NotWriter(ostream & oo) : o(oo) {};
+
+	template<class typ>
+	void operator()(const typ * p) {o << " (not "; p->typ::write(o);o << ")";};
+};
