+	{
+		o << " ";
+		if(dynamic_cast<var_symbol*>(*i)) 
+		{
+			dynamic_cast<var_symbol*>(*i)->var_symbol::write(o);
+		}
+		else
+		{
+			dynamic_cast<const_symbol*>(*i)->const_symbol::write(o);
+		};
+	};
