+void RelaxTranslator::write_assignment(ostream & o,const assignment * p)
+{
+
+ 	o << "(";
+	switch(p->getOp())
+	{
+		case E_ASSIGN:
+			if(inInitial) 
+			{
+				o << "= ";
+			}
+			else 
+			{
+				o << "assign ";
+			};
+			break;
+		case E_INCREASE:
+			o << "increase ";
+			break;
+		case E_DECREASE:
+			o << "decrease ";
+			break;
+		case E_SCALE_UP:
+			o << "scale-up ";
+			break;
+		case E_SCALE_DOWN:
+			o << "scale-down ";
+			break;
+		default:
+			break;
+	};
+	p->getFTerm()->write(o);
+	o << " ";
+	if(showFixedEffect)
+	{ 
+		o << "10"; // Here we need to think! 
+	}
+	else p->getExpr()->write(o);
+	o << ")";
+
+};
