+double getStandardDev(double noTests,double numberOfInvalidPlans,double mean)
+{
+ double sum = numberOfInvalidPlans*mean*mean + (noTests - numberOfInvalidPlans)*(1.0 - mean)*(1.0 - mean);
+ 
+ return sqrt(sum/noTests);  
+};
