+       *report << "\\item ";
+        if(estProbValidPlan != 1 && estProbValidPlan != 0)
+       *report << "There is a 95$\\%$ chance that the plan has a valid execution with probability in the range "<< estProbValidPlan*100.0 << " $\\pm$"<< errorLimit*100.0 <<".\\\\\n";
