+	InitialStateEvaluator(bool & v,bool & u, bool & w, bool & x):
+		PrimitiveEvaluator(v,u,w,x)
+	{};
+	static void setInitialState();
+	virtual void evaluateSimpleGoal(VAL::FastEnvironment * f,VAL::simple_goal * s);
+};
