+	
+	bool reallyTrue() const
+	{
+		return !unknownTrue && valueTrue;
+	};
+	bool reallyFalse() const
+	{
+		//return !unknownTrue && !valueTrue;
+		return !unknownFalse && valueFalse;
+	};
+
